const result = [];

// Iteramos sobre cada registro
for (const item of $input.all()) {
  let data = item.json;
  let errors = [];

  // --- 1. LIMPIEZA DE DATOS ---
  const cleanText = (str) => (typeof str === 'string' ? str.trim().toUpperCase() : '');

  data.primer_nombre = cleanText(data.primer_nombre);
  data.segundo_nombre = cleanText(data.segundo_nombre);
  data.primer_apellido = cleanText(data.primer_apellido);
  data.segundo_apellido = cleanText(data.segundo_apellido);
  data.regional = cleanText(data.regional);
  data.municipio = cleanText(data.municipio);

  if (data.documento) data.documento = data.documento.toString().replace(/\D/g, '');
  if (data.telefono) data.telefono = data.telefono.toString().replace(/\D/g, '');

  if (data.edad) {
    data.edad = parseInt(data.edad, 10);
  }

  // --- 2. VALIDACIÓN ---
  if (!data.documento || data.documento === '') {
    errors.push("Documento vacío o inválido");
  }
  if (!data.primer_nombre || data.primer_nombre === '') {
    errors.push("Falta el primer nombre");
  }
  if (!data.tipo_documento) {
    errors.push("Falta tipo de documento");
  }


  // --- 3. ETIQUETADO (Para separar luego en el nodo If) ---
  // Creamos una nueva propiedad booleana
  data.es_valido = errors.length === 0;

  // Si hay errores, guardamos el motivo
  if (!data.es_valido) {
    data.motivo_error = errors.join(", ");
  }

  // Agregamos el ítem al arreglo final
  result.push({ json: data });
}

return result;

