const cleanedItems = [];

for (const item of $input.all()) {
  try {
    const rawData = JSON.parse(item.json.data);
    const entries = rawData.entry || [];

    let patientData = null;
    let operationOutcome = null;

    entries.forEach(entry => {
      if (entry.resource.resourceType === 'Patient') {
        patientData = entry.resource;
      } else if (entry.resource.resourceType === 'OperationOutcome') {
        operationOutcome = entry.resource;
      }
    });

    if (!patientData) {
      cleanedItems.push({ json: { error: "No se encontró información del paciente" } });
      continue;
    }

    const getExt = (url) => patientData.extension?.find(e => e.url?.endsWith(url));

    const estadoAfiliado = getExt('afilliateStatus')?.valueCoding?.display || 'Desconocido';
    const estaActivo = estadoAfiliado === 'ACTIVO';
    const estaFallecido = estadoAfiliado === 'AFILIADO FALLECIDO';

    const direccion = patientData.address?.[0];
    const zona = direccion?.extension?.find(e => e.url?.endsWith('zone'))?.valueString || '';
    const ubicacion = direccion?.extension?.find(e => e.url?.endsWith('location'))?.valueString || '';

    const placeOfCare = getExt('placeOfCare');
    const nomDep = placeOfCare?.extension?.find(e => e.url?.endsWith('state'))?.valueCoding?.display || '';
    const nomMun = placeOfCare?.extension?.find(e => e.url?.endsWith('city'))?.valueCoding?.display || '';
    const depCod = placeOfCare?.extension?.find(e => e.url?.endsWith('state'))?.valueCoding?.code || '';
    const munCodRaw = placeOfCare?.extension?.find(e => e.url?.endsWith('city'))?.valueCoding?.code || '';

    // Eliminar el código del departamento del inicio del código de municipio
    // Ejemplo: "13657" con depCod "13" → "657" | "08001" con depCod "08" → "001"
    const munCod = munCodRaw.startsWith(depCod) ? munCodRaw.slice(depCod.length) : munCodRaw;

    // Extraer tipo y número de documento
    const tipoDoc = patientData.identifier?.find(i => i.type?.coding?.[0]?.code === 'DT')?.value || '';
    const numDoc = patientData.identifier?.find(i => i.type?.coding?.[0]?.code === 'DI')?.value || '';

    const resultado = {
      // --- Identificación ---
      tipo_documento: tipoDoc,
      numero_documento: numDoc,

      // --- Estado ---
      status: operationOutcome?.issue[0]?.details?.text || 'Desconocido',
      estado_afiliado: estadoAfiliado,
      esta_activo: estaActivo,
      esta_fallecido: estaFallecido,

      // --- Datos personales ---
      nombre_completo: patientData.name?.[0]?.text || '',
      primer_nombre: patientData.name?.[0]?.given?.[0] || '',
      segundo_nombre: patientData.name?.[0]?.given?.[1] || '',
      primer_apellido: patientData.name?.[0]?.family?.split('firstSurname=')?.[1]?.split('|')?.[0] || '',
      segundo_apellido: patientData.name?.[0]?.family?.split('secondSurname=')?.[1] || '',
      fecha_nacimiento: patientData.birthDate || '',
      genero: patientData.gender || '',
      edad: getExt('age')?.valueInteger || null,

      // --- Contacto ---
      telefono_fijo: patientData.telecom?.find(t => t.use === 'home')?.value || '',
      telefono_movil: patientData.telecom?.find(t => t.use === 'mobile')?.value || '',
      email: patientData.telecom?.find(t => t.system === 'email')?.value || '',

      // --- Dirección ---
      direccion_texto: direccion?.text || '',
      ciudad: direccion?.city || '',
      departamento: direccion?.state || '',
      zona: zona,
      ubicacion: ubicacion,

      // --- Afiliación ---
      regimen: getExt('healthModality')?.valueCoding?.display || '',
      regimen_codigo: getExt('healthModality')?.valueCoding?.code || '',
      tipo_afiliado: getExt('affiliateType')?.valueCoding?.display || '',
      codigo_afiliado: getExt('affiliateType')?.valueCoding?.code || '',
      tipo_usuario: getExt('entityCode')?.valueCoding?.display || '',
      codigo_empresa: getExt('entityCode')?.valueCoding?.code || '',
      fecha_afiliacion: getExt('affiliationDate')?.valueDate || '',

      // --- Lugar de atención ---
      nombre_departamento: nomDep,
      codigo_departamento: depCod,
      nombre_municipio: nomMun,
      codigo_municipio: munCod,
    };

    if (estaFallecido) {
      resultado.fecha_fallecimiento = getExt('dateOfDeath')?.valueDate || '';
    }

    cleanedItems.push({ json: resultado });

  } catch (error) {
    cleanedItems.push({
      json: {
        error: "Fallo al parsear la data de la API",
        details: error.message
      }
    });
  }
}

return cleanedItems;

const staticData = $getWorkflowStaticData('global');
const tokenZeus = $input.item.json.BearerToken;

// Decodifica el JWT y lee la expiración real
const payload = JSON.parse(Buffer.from(tokenZeus.split('.')[1], 'base64').toString());
const expiryMs = (payload.exp * 1000) - (60 * 1000); // 1 minuto de margen

staticData.tokenZeus = tokenZeus;
staticData.tokenZeusExpiry = expiryMs;

return [{
  json: {
    datos: [...$("Seleccionar usuarios que esten activos sin autoid").all()],
    tokenZeus: tokenZeus,
    tokenValidoZeus: true,
    expiraEl: new Date(expiryMs).toISOString()
  }
}];

return $input.all().map(item => {
  const { tipo_documento, documento, nombre_examen, fecha_toma_examen } = item.json;

  const id_registro = Buffer.from(
    `${tipo_documento}|${documento}|${nombre_examen}|${fecha_toma_examen}`
  ).toString('base64').replace(/=+$/, '');

  return { json: { ...item.json, id_registro } };
});

